import "./App.css";
import Footer from "./Components/Footer/Footer";
import Home from "./Components/Home/Home";
import Main from "./Components/Main/Main";
import Navbar from "./Components/Navbar/navbar";
import { cars } from "./Components/SliderImages";
import React, { useRef, useEffect } from "react";

function App() {
  const myTargetRef = useRef(null);
  const scrollToTarget = () => {
    myTargetRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
  };
  return (
    <div>
      <Navbar />
      <Home />
      <div className="scrollDown" onClick={scrollToTarget}>
        <span></span>
        <span></span>
        <span></span>
      </div>
      <Main ref={myTargetRef} images={cars} />
      <Footer />
    </div>
  );
}

export default App;
